class Solution:
    def minAreaFreeRect(self, points):
        import math
        pts = set(map(tuple, points))
        plist = [tuple(p) for p in points]
        n = len(plist)
        best = float('inf')
        for i in range(n):
            for j in range(n):
                if j == i:
                    continue
                for k in range(n):
                    if k == i or k == j:
                        continue
                    p1, p2, p3 = plist[i], plist[j], plist[k]
                    v1 = (p2[0] - p1[0], p2[1] - p1[1])
                    v2 = (p3[0] - p1[0], p3[1] - p1[1])
                    if v1[0] * v2[0] + v1[1] * v2[1] != 0:
                        continue
                    p4 = (p2[0] + v2[0], p2[1] + v2[1])
                    if p4 in pts:
                        area = math.hypot(*v1) * math.hypot(*v2)
                        best = min(best, area)
        return 0.0 if best == float('inf') else best

