var minAreaFreeRect = function(points) {
    const groups = new Map();
    const n = points.length;
    for (let i = 0; i < n; i++) {
        for (let j = i + 1; j < n; j++) {
            const [x1, y1] = points[i];
            const [x2, y2] = points[j];
            const cx = x1 + x2, cy = y1 + y2;
            const d2 = (x1 - x2) ** 2 + (y1 - y2) ** 2;
            const key = cx + ',' + cy + ',' + d2;
            if (!groups.has(key)) groups.set(key, []);
            groups.get(key).push([points[i], points[j]]);
        }
    }
    let best = Infinity;
    for (const pairs of groups.values()) {
        const m = pairs.length;
        for (let a = 0; a < m; a++) {
            for (let b = a + 1; b < m; b++) {
                const [p1] = pairs[a];
                const [p3, p4] = pairs[b];
                const v1 = [p3[0] - p1[0], p3[1] - p1[1]];
                const v2 = [p4[0] - p1[0], p4[1] - p1[1]];
                const area = Math.hypot(v1[0], v1[1]) * Math.hypot(v2[0], v2[1]);
                if (area < best) best = area;
            }
        }
    }
    return best === Infinity ? 0.0 : best;
};
